// // This module implements a 3-input SVM decision function with weights 1, 2, and 1 for x1, x2, and x3 respectively.
module svm_decision_function (
    input wire x1,
    input wire x2,
    input wire x3,
    output wire y
);
    assign y = (x1 * 1 + x2 * 2 + x3 * 1) > 1 ? 1 : 0;
endmodule
